// 产 PDF 字节;需 jsPDF peer;零 DOM 足迹
import { jsPDF } from 'https://cdn.jsdelivr.net/npm/jspdf@4.2.1/+esm';
import autoTable from 'https://cdn.jsdelivr.net/npm/jspdf-autotable@5.0.8/+esm';
const doc = new jsPDF();
autoTable(doc, {
  head: data.head,
  body: data.body,
  foot: data.foot,
  startY: data.startY,
  theme: data.theme ?? 'striped',
  styles: data.styles,
  headStyles: data.headStyles,
  columnStyles: data.columnStyles,
  margin: data.margin
});
const blob = doc.output('blob');
